// Replays flutter/test/goldens/bnpl_goldens.json, generated by executing
// the REAL mobile/lib/bnpl.js. Every total, rate, and verdict flag must
// match the live app exactly.

import 'dart:convert';
import 'dart:io';

import 'package:flutter_test/flutter_test.dart';
import 'package:salapify/money/bnpl.dart';

dynamic normalize(dynamic v) {
  if (v is num) return v.toDouble().isFinite ? v.toDouble() : null;
  if (v is Map) return v.map((k, x) => MapEntry(k.toString(), normalize(x)));
  if (v is List) return v.map(normalize).toList();
  return v;
}

void main() {
  final raw = jsonDecode(
      File('test/goldens/bnpl_goldens.json').readAsStringSync())
      as Map<String, dynamic>;

  test('bnplCost matches the RN engine on every vector', () {
    for (final c in (raw['cases'] as List).cast<Map<String, dynamic>>()) {
      final fields = c['fields'] != null
          ? (c['fields'] as Map).cast<String, dynamic>()
          : null;
      final result = normalize(bnplCost(fields)) as Map;
      final expected = normalize(c['result']) as Map;
      // The two raw rate fields come from 200 bisection iterations over
      // pow(), where V8 and Dart libm differ by ulps (the 15th decimal).
      // The screen displays one decimal, so compare those to 1e-9 relative
      // and everything else exactly.
      for (final key in ['monthlyRate', 'annualRate']) {
        final got = (result.remove(key) as double?) ?? 0;
        final want = (expected.remove(key) as double?) ?? 0;
        expect(got, closeTo(want, (want.abs() + 1) * 1e-9),
            reason: '${c['name']}: $key');
      }
      expect(result, expected, reason: c['name'] as String);
    }
  });
}
